1	type Item = { type: string; cursed?: boolean };
2	
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: { op: "quote"; items: Item[] }[];
6	};
7	
8	type ScenarioResult = {
9	  results: { premium: number }[];
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const firstInsuranceSurcharge = (premium: number): number => premium / 10;
15	
16	const COMPONENT_PREMIUM = 25;
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: COMPONENT_PREMIUM,
24	  moonstone: COMPONENT_PREMIUM,
25	};
26	
27	const BLOCK_PREMIUM = 60;
28	
29	const isBlock = (count: number): boolean => count === 3;
30	
31	const countByType = (items: Item[]): Record<string, number> =>
32	  items.reduce<Record<string, number>>((counts, item) => {
33	    counts[item.type] = (counts[item.type] ?? 0) + 1;
34	    return counts;
35	  }, {});
36	
37	const premiumForGroup = (type: string, count: number): number =>
38	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
39	
40	const basePremiumFor = (items: Item[]): number =>
41	  Object.entries(countByType(items)).reduce(
42	    (total, [type, count]) => total + premiumForGroup(type, count),
43	    0,
44	  );
45	
46	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
47	
48	const curseSurchargeFor = (items: Item[]): number =>
49	  items.reduce(
50	    (total, item) => total + (item.cursed ? BASE_PREMIUMS[item.type] / 2 : 0),
51	    0,
52	  );
53	
54	const quotePremium = (items: Item[]): number => {
55	  const basePremium = basePremiumFor(items);
56	  return roundUpToWholeGold(
57	    basePremium +
58	      curseSurchargeFor(items) +
59	      firstInsuranceSurcharge(basePremium) +
60	      PROCESSING_FEE,
61	  );
62	};
63	
64	export const runScenario = (scenario: Scenario): ScenarioResult => ({
65	  results: [{ premium: quotePremium(scenario.steps[0].items) }],
66	});
